class MongoDBAdvancedFilter:
    def __init__(self, connection_string: str, database_name: str, collection_name: str):
        self.client = MongoClient(connection_string)
        self.db = self.client[database_name]
        self.collection = self.db[collection_name]
    
    def execute_where_query(self, js_expression: str, projection: Optional[Dict] = None, 
                           limit: int = 100) -> List[Dict[str, Any]]:
        query = {"$where": js_expression}
        cursor = self.collection.find(query, projection).limit(limit)
        return list(cursor)
    
    def execute_custom_filter(self, filter_expression: str, additional_filters: Optional[Dict] = None,
                             projection: Optional[Dict] = None, limit: int = 100) -> List[Dict[str, Any]]:
        query = {"$where": filter_expression}
        if additional_filters:
            query.update(additional_filters)
        cursor = self.collection.find(query, projection).limit(limit)
        return list(cursor)
    
    def execute_complex_aggregation_with_where(self, js_expression: str, 
                                               pipeline: Optional[List[Dict]] = None) -> List[Dict[str, Any]]:
        if pipeline is None:
            pipeline = []
        
        match_stage = {"$match": {"$where": js_expression}}
        full_pipeline = [match_stage] + pipeline
        
        return list(self.collection.aggregate(full_pipeline))
    
    def execute_conditional_filter(self, field_conditions: Dict[str, str]) -> List[Dict[str, Any]]:
        js_parts = []
        for field, condition in field_conditions.items():
            js_parts.append(f"this.{field} {condition}")
        
        js_expression = " && ".join(js_parts)
        return self.execute_where_query(js_expression)
    
    def execute_function_based_filter(self, js_function: str, limit: int = 100) -> List[Dict[str, Any]]:
        return self.execute_where_query(js_function, limit=limit)
    
    def find_with_computed_fields(self, js_expression: str, sort_field: Optional[str] = None,
                                  sort_order: int = 1, limit: int = 100) -> List[Dict[str, Any]]:
        query = {"$where": js_expression}
        cursor = self.collection.find(query).limit(limit)
        
        if sort_field:
            cursor = cursor.sort(sort_field, sort_order)
        
        return list(cursor)
    
    def execute_multi_field_comparison(self, field1: str, operator: str, field2: str,
                                      limit: int = 100) -> List[Dict[str, Any]]:
        js_expression = f"this.{field1} {operator} this.{field2}"
        return self.execute_where_query(js_expression, limit=limit)
    
    def execute_regex_filter(self, field: str, pattern: str, flags: str = "",
                            limit: int = 100) -> List[Dict[str, Any]]:
        js_expression = f"/{pattern}/{flags}.test(this.{field})"
        return self.execute_where_query(js_expression, limit=limit)
    
    def execute_array_filter(self, array_field: str, js_condition: str,
                            limit: int = 100) -> List[Dict[str, Any]]:
        js_expression = f"this.{array_field} && this.{array_field}.some(function(item) {{ return {js_condition}; }})"
        return self.execute_where_query(js_expression, limit=limit)
    
    def execute_nested_field_filter(self, js_expression: str, limit: int = 100) -> List[Dict[str, Any]]:
        return self.execute_where_query(js_expression, limit=limit)
    
    def execute_date_comparison(self, date_field: str, comparison: str,
                               limit: int = 100) -> List[Dict[str, Any]]:
        js_expression = f"this.{date_field} && new Date(this.{date_field}) {comparison}"
        return self.execute_where_query(js_expression, limit=limit)
    
    def execute_mathematical_filter(self, js_math_expression: str,
                                   limit: int = 100) -> List[Dict[str, Any]]:
        return self.execute_where_query(js_math_expression, limit=limit)
    
    def execute_string_manipulation_filter(self, field: str, js_string_operation: str,
                                          limit: int = 100) -> List[Dict[str, Any]]:
        js_expression = f"this.{field} && this.{field}.{js_string_operation}"
        return self.execute_where_query(js_expression, limit=limit)
    
    def execute_custom_logic_filter(self, js_function_body: str, limit: int = 100) -> List[Dict[str, Any]]:
        js_expression = f"function() {{ {js_function_body} }}()"
        return self.execute_where_query(js_expression, limit=limit)
    
    def execute_combined_filters(self, where_expression: str, mongo_query: Dict,
                                projection: Optional[Dict] = None, limit: int = 100) -> List[Dict[str, Any]]:
        combined_query = {"$where": where_expression}
        combined_query.update(mongo_query)
        cursor = self.collection.find(combined_query, projection).limit(limit)
        return list(cursor)
    
    def count_with_where(self, js_expression: str) -> int:
        query = {"$where": js_expression}
        return self.collection.count_documents(query)
    
    def execute_distinct_with_where(self, field: str, js_expression: str) -> List[Any]:
        query = {"$where": js_expression}
        return self.collection.distinct(field, query)
    
    def close(self):
        self.client.close()


class AdvancedDataFilteringService:
    def __init__(self, connection_string: str, database_name: str):
        self.connection_string = connection_string
        self.database_name = database_name
        self.filters = {}
    
    def create_filter_session(self, session_id: str, collection_name: str) -> MongoDBAdvancedFilter:
        filter_instance = MongoDBAdvancedFilter(self.connection_string, self.database_name, collection_name)
        self.filters[session_id] = filter_instance
        return filter_instance
    
    def get_filter_session(self, session_id: str) -> Optional[MongoDBAdvancedFilter]:
        return self.filters.get(session_id)
    
    def close_filter_session(self, session_id: str):
        if session_id in self.filters:
            self.filters[session_id].close()
            del self.filters[session_id]
    
    def close_all_sessions(self):
        for session_id in list(self.filters.keys()):
            self.close_filter_session(session_id)


